  const announce = useCallback((message: string) => {
    queueRef.current.push(message);
    if (!isAnnouncingRef.current) {
      processQueue();
    }
  }, []);

  const processQueue = useCallback(() => {
    if (queueRef.current.length === 0) {
      isAnnouncingRef.current = false;
      return;
    }

    isAnnouncingRef.current = true;
    const next = queueRef.current.shift();
    setAnnouncement(next || null);

    setTimeout(() => {
      setAnnouncement(null);
      setTimeout(processQueue, 500); // 500ms gap between speech
    }, 2000); // Speech duration simulation
  }, []);

  // Accessibility Node 5: Focus Trap Hook (Simplified for React)
  const useFocusTrap = (isActive: boolean) => {
    const containerRef = useRef<HTMLDivElement>(null);

    useEffect(() => {
      if (!isActive) return;

      const handleTab = (e: KeyboardEvent) => {
        if (!containerRef.current || e.key !== 'Tab') return;

        const focusable = containerRef.current.querySelectorAll(
          'button, [href], input, select, textarea, [tabindex]:not([tabindex="-1"])'
        );
        const first = focusable[0] as HTMLElement;
        const last = focusable[focusable.length - 1] as HTMLElement;

        if (e.shiftKey) {
          if (document.activeElement === first) {
            last.focus();
            e.preventDefault();
          }
        } else {
          if (document.activeElement === last) {
            first.focus();
            e.preventDefault();
          }
        }
      };

      window.addEventListener('keydown', handleTab);
      return () => window.removeEventListener('keydown', handleTab);
    }, [isActive]);

    return containerRef;
  };

  return { announce, announcement, useFocusTrap };
}

import { useState, useCallback, useEffect, useRef } from 'react';

/**
 * useHashWorker (Efficiency Node 10)
 * Manages the lifecycle of the VVPAT Hashing Web Worker.
 */
export function useHashWorker() {
  const workerRef = useRef<Worker | null>(null);
  const [isHashing, setIsHashing] = useState(false);

  useEffect(() => {
    workerRef.current = new Worker(new URL('../workers/hash.worker.ts', import.meta.url));
    return () => workerRef.current?.terminate();
  }, []);

  const generateVVPAT = useCallback((data: string, visitorId: string): Promise<{ hash: string; fullHash: string }> => {
    return new Promise((resolve, reject) => {
      if (!workerRef.current) return reject('Worker not initialized');

      setIsHashing(true);
      workerRef.current.onmessage = (e) => {
        setIsHashing(false);
        if (e.data.error) reject(e.data.error);
        else resolve(e.data);
      };

      workerRef.current.postMessage({ data, visitorId });
    });
  }, []);

  return { generateVVPAT, isHashing };
}

