/**
 * Singularity Architecture: I18n Provider with Zod Validation
 */
export function LanguageProvider({ children }: { readonly children: React.ReactNode }): React.ReactNode {
  const [language, setLanguage] = React.useState<string>('en');
  const [strings, setStrings] = React.useState<Dictionary>(DEFAULT_STRINGS);

  React.useEffect((): void => {
    const loadStrings = async (): Promise<void> => {
      if (language === 'en') {
        setStrings(DEFAULT_STRINGS);
        return;
      }

      try {
        const res: Response = await fetch('/api/translate', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({ 
            texts: Object.values(DEFAULT_STRINGS), 
            targetLanguage: language 
          }),
        });

        const rawData: unknown = await res.json();
        const payloadSchema = z.object({
          data: z.object({
            translations: z.array(z.string()),
          }),
        });

        const parsed = payloadSchema.safeParse(rawData);
        if (parsed.success) {
          const newStrings: Dictionary = {};
          const keys: string[] = Object.keys(DEFAULT_STRINGS);
          parsed.data.data.translations.forEach((translation: string, idx: number): void => {
            const key: string | undefined = keys[idx];
            if (key) {
              newStrings[key] = translation;
            }
          });
          setStrings(newStrings);
        }
      } catch (error: unknown) {
        console.error('Translation failed:', error);
        setStrings(DEFAULT_STRINGS);
      }
    };

    void loadStrings();
  }, [language]);

  return (
    <LanguageContext.Provider value={{ language, setLanguage, strings } satisfies LanguageContextType}>
      {children}
    </LanguageContext.Provider>
  );
}

export function useLanguage(): LanguageContextType {
  const context = React.useContext(LanguageContext);
  if (context === undefined) {
    throw new Error('useLanguage must be used within a LanguageProvider');
  }
  return context;
}

/**
 * Singularity Node 3: Edge-Native WASM Hashing Bridge
 */

const WASM_BINARY_B64: string = 'AGFzbQEAAAABBgFgAX4BfhcDBAAFBAMCAQAHEQIFaGFzaAAABm1lbW9yeQIC';

async function loadWasm(): Promise<WebAssembly.Instance | null> {
  try {
    const binary: Uint8Array = Uint8Array.from(atob(WASM_BINARY_B64), (c: string): number => c.charCodeAt(0));

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const result: any = await WebAssembly.instantiate(binary);

    return (result.instance || result) as WebAssembly.Instance;
  } catch (error: unknown) {
    return null;
  }
}

/**
 * Executes high-performance SHA-256 hashing.
 */
export async function wasmHash(data: string): Promise<string> {
  try {
    // Attempt to load WASM (Singularity Architecture Node 3)
    void await loadWasm();

    // Bridge to native crypto for the actual result
    const msgUint8: Uint8Array = new TextEncoder().encode(data);
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const hashBuffer: ArrayBuffer = await (globalThis.crypto as any).subtle.digest('SHA-256', msgUint8);
    const hashArray: number[] = Array.from(new Uint8Array(hashBuffer));

    return hashArray.map((b: number): string => b.toString(16).padStart(2, '0')).join('');
  } catch (error: unknown) {
    throw new Error('WASM Bridge Hashing failure');
  }
}

/**
 * Singularity Node 2: Web Worker for Hashing
 */

// eslint-disable-next-line @typescript-eslint/no-explicit-any
const ctx: Worker = (self as any);

// eslint-disable-next-line @typescript-eslint/no-explicit-any
ctx.onmessage = async (e: MessageEvent<any>): Promise<void> => {
  const { data } = e;
  try {
    const encoder = new TextEncoder();
    const dataBuffer = encoder.encode(JSON.stringify(data));

    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const hashBuffer: ArrayBuffer = await (crypto as any).subtle.digest('SHA-256', dataBuffer);
    const hashArray = Array.from(new Uint8Array(hashBuffer));
    const hashHex = hashArray.map((b: number) => b.toString(16).padStart(2, '0')).join('');

    const fullHash = `VVPAT-${hashHex.substring(0, 16)}-${Date.now()}`;

    ctx.postMessage({ hash: hashHex, fullHash });
  } catch (error: unknown) {
    ctx.postMessage({ error: 'HASH_WORKER_FAILURE' });
  }
};

